class Solution(object):
    def alternatingSubarray(self, nums):
        n = len(nums)
        res = -1
        for i in range(n - 1):
            if nums[i + 1] - nums[i] == 1:
                length = 2
                res = max(res, length)
                for j in range(i + 2, n):
                    expected = 1 if (j - i) % 2 == 1 else -1
                    if nums[j] - nums[j - 1] == expected:
                        length += 1
                        res = max(res, length)
                    else:
                        break
        return res
